module top_module(
    A,
    B,
    C,
    D,
    X,
    VPWR,
    VGND
);input A;
    input B;
    input C;
    input D;
    output X;
    input VPWR;
    input VGND;

    wire not_ab, cd, abcd;

    // Replaced 'sky130_fd_sc_hs__xnor3' with 'xnor' for standard xnor functionality.
    assign not_ab = ~(A ^ B);
    assign cd = ~(C ^ D);
    assign abcd = ~(not_ab ^ cd);

    assign X = abcd;

endmodule
